     * Path covers B0→B1 (first getNextToken() returns null) → B7→B9→B11.
     */
    @Test
    @DisplayName("Empty expression returns empty token list without exceptions")
    public void test_TC01() throws ParseException {
        ExpressionConfiguration config = new ExpressionConfiguration(true, true); // updated constructor
        Tokenizer tokenizer = new Tokenizer("", config);
        List<Token> tokens = tokenizer.parse();
        assertTrue(tokens.isEmpty(), "An empty expression should yield no tokens");
    }

    /**
     * TC02: Single number literal parsed and returned
     * Path covers B0→B1→B2 false (no implicit multiplication) → B6→B1→B7→B9→B11.
     */
    @Test
    @DisplayName("Single number literal parsed and returned")
    public void test_TC02() throws ParseException {
        ExpressionConfiguration config = new ExpressionConfiguration(true, true); // updated constructor
        // "123" is a single decimal literal
        Tokenizer tokenizer = new Tokenizer("123", config);
        List<Token> tokens = tokenizer.parse();
        assertEquals(1, tokens.size(), "Should parse exactly one token");
        Token t = tokens.get(0);
        assertAll("Verify number literal token",
            () -> assertEquals(TokenType.NUMBER_LITERAL, t.getType()),
            () -> assertEquals("123", t.getValue())
        );
    }

